  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { evaluateIntent, createLlmEvaluator } from "./authorizer";
  3→import type { LlmEvaluator } from "./authorizer";
  4→import { updateIntentStatus, getIntentById } from "./intent-queries";
  5→import { routeByRisk } from "./risk-router";
  6→import type { IntentRecord, EvaluationResult } from "./types";
  7→import type { ServerDependencies } from "../runtime/types";
  8→import {
  9→  findAlignedObjectivesSurreal,
 10→  createSupportsEdgeSurreal,
 11→  createAlignmentWarningObservation,
 12→} from "../objective/alignment-adapter";
 13→
 14→type EvaluatePendingIntentDeps = {
 15→  surreal: Surreal;
 16→  extractionModel?: ServerDependencies["extractionModel"];
 17→  llmEvaluator?: LlmEvaluator;
 18→};
 19→
 20→type EvaluatedStatus = "authorized" | "pending_veto" | "vetoed";
 21→
 22→type EvaluatedIntent = {
 23→  intentId: string;
 24→  status: EvaluatedStatus;
 25→  evaluation: EvaluationResult & {
 26→    evaluated_at: Date;
 27→    policy_only: boolean;
 28→    policy_trace?: import("../policy/types").PolicyTraceEntry[];
 29→    human_veto_required?: boolean;
 30→  };
 31→  vetoExpiresAt?: Date;
 32→};
 33→
 34→type EvaluatePendingIntentResult =
 35→  | { ok: true; value: EvaluatedIntent }
 36→  | { ok: false; error: string; httpStatus: number };
 37→
 38→type EvaluatePendingIntentOptions = {
 39→  intent?: IntentRecord;
 40→};
 41→
 42→function resolveRecordId<T extends string>(
 43→  table: T,
 44→  ref: unknown,
 45→): RecordId<T> {
 46→  const rawId = typeof ref === "object" && ref !== null
 47→    ? ((ref as { id: unknown }).id as string)
 48→    : String(ref);
 49→  return new RecordId(table, rawId);
 50→}
 51→
 52→type TransitionPlan = {
 53→  targetStatus: EvaluatedStatus;
 54→  updateFields: Record<string, unknown>;
 55→  status: EvaluatedStatus;
 56→  vetoExpiresAt?: Date;
 57→};
 58→
 59→function toTransition(
 60→  routing: ReturnType<typeof routeByRisk>,
 61→  evaluationRecord: EvaluatedIntent["evaluation"],
 62→): TransitionPlan {
 63→  switch (routing.route) {
 64→    case "auto_approve":
 65→      return {
 66→        targetStatus: "authorized",
 67→        status: "authorized",
 68→        updateFields: { evaluation: evaluationRecord },
 69→      };
 70→    case "veto_window":
 71→      return {
 72→        targetStatus: "pending_veto",
 73→        status: "pending_veto",
 74→        updateFields: { evaluation: evaluationRecord, veto_expires_at: routing.expires_at },
 75→        vetoExpiresAt: routing.expires_at,
 76→      };
 77→    case "reject":
 78→      return {
 79→        targetStatus: "vetoed",
 80→        status: "vetoed",
 81→        updateFields: { evaluation: evaluationRecord },
 82→      };
 83→  }
 84→}
 85→
 86→export async function evaluatePendingIntent(
 87→  intentId: string,
 88→  deps: EvaluatePendingIntentDeps,
 89→  options?: EvaluatePendingIntentOptions,
 90→): Promise<EvaluatePendingIntentResult> {
 91→  const intent = options?.intent ?? await getIntentById(deps.surreal, intentId);
 92→  if (!intent) {
 93→    return { ok: false, error: "Intent not found", httpStatus: 404 };
 94→  }
 95→
 96→  if (intent.status !== "pending_auth") {
 97→    return {
 98→      ok: false,
 99→      error: `Intent is in '${intent.status}' status, expected 'pending_auth'`,
100→      httpStatus: 409,
101→    };
102→  }
103→
104→  const identityId = resolveRecordId("identity", intent.requester);
105→  const workspaceRecord = resolveRecordId("workspace", intent.workspace);
106→  const intentRecord = new RecordId("intent", intentId);
107→
108→  const [identityRows] = await deps.surreal.query<[Array<{ type?: string; role?: string }>]>(
109→    `SELECT type, role FROM $identity;`,
110→    { identity: identityId },
111→  );
112→  const identityInfo = identityRows[0];
113→
114→  const llmEvaluator = deps.llmEvaluator
115→    ?? (deps.extractionModel ? createLlmEvaluator(deps.extractionModel) : undefined);
116→  if (!llmEvaluator) {
117→    return { ok: false, error: "Missing evaluator model", httpStatus: 500 };
118→  }
119→  const evaluation = await evaluateIntent({
120→    intent: {
121→      goal: intent.goal,
122→      reasoning: intent.reasoning,
123→      action_spec: intent.action_spec,
124→      budget_limit: intent.budget_limit,
125→      priority: intent.priority,
126→    },
127→    surreal: deps.surreal,
128→    identityId,
129→    workspaceId: workspaceRecord,
130→    requesterType: identityInfo?.type ?? "agent",
131→    requesterRole: identityInfo?.role,
132→    llmEvaluator,
133→    intentId: intentRecord,
134→    intentText: intent.goal,
135→    findAlignedObjectives: findAlignedObjectivesSurreal(deps.surreal),
136→    createSupportsEdge: createSupportsEdgeSurreal(deps.surreal),
137→    createAlignmentWarning: (ws, iId, score) =>
138→      createAlignmentWarningObservation(deps.surreal, ws, iId, score),
139→  });
140→
141→  // Strip `alignment` — it's used in-memory but not defined in the intent schema
142→  const { alignment: _alignment, ...evaluationForDb } = evaluation;
143→  const evaluationRecord: EvaluatedIntent["evaluation"] = {
144→    ...evaluationForDb,
145→    evaluated_at: new Date(),
146→  };
147→  const routing = routeByRisk(evaluation, {
148→    humanVetoRequired: evaluation.human_veto_required,
149→  });
150→  const transition = toTransition(routing, evaluationRecord);
151→
152→  const result = await updateIntentStatus(
153→    deps.surreal,
154→    intentId,
155→    transition.targetStatus,
156→    transition.updateFields,
157→  );
158→  if (!result.ok) {
159→    return { ok: false, error: result.error, httpStatus: 409 };
160→  }
161→
162→  return {
163→    ok: true,
164→    value: {
165→      intentId,
166→      status: transition.status,
167→      evaluation: evaluationRecord,
168→      ...(transition.vetoExpiresAt ? { vetoExpiresAt: transition.vetoExpiresAt } : {}),
169→    },
170→  };
171→}
