  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { IntentRecord, IntentStatus, ActionSpec, BudgetLimit, EvaluationResult } from "./types";
  3→import type { BrainAction } from "../oauth/types";
  4→import { transitionStatus } from "./status-machine";
  5→
  6→// --- Query Result Types ---
  7→
  8→type CreateIntentParams = {
  9→  goal: string;
 10→  reasoning: string;
 11→  priority: number;
 12→  action_spec: ActionSpec;
 13→  budget_limit?: BudgetLimit;
 14→  trace_id: RecordId<"trace", string>;
 15→  requester: RecordId<"identity", string>;
 16→  workspace: RecordId<"workspace", string>;
 17→  expiry?: Date;
 18→  authorization_details?: BrainAction[];
 19→  dpop_jwk_thumbprint?: string;
 20→};
 21→
 22→type StatusUpdateFields = {
 23→  evaluation?: EvaluationResult & { evaluated_at: Date; policy_only: boolean };
 24→  veto_expires_at?: Date;
 25→  veto_reason?: string;
 26→  error_reason?: string;
 27→};
 28→
 29→type ListFilters = {
 30→  status?: IntentStatus;
 31→  limit?: number;
 32→};
 33→
 34→// --- Trace Creation ---
 35→
 36→export type TraceType = "tool_call" | "message" | "subagent_spawn" | "intent_submission" | "bridge_exchange";
 37→
 38→export type CreateTraceParams = {
 39→  type: TraceType;
 40→  actor: RecordId<"identity", string>;
 41→  workspace: RecordId<"workspace", string>;
 42→  session?: RecordId<"agent_session", string>;
 43→  parent_trace?: RecordId<"trace", string>;
 44→  tool_name?: string;
 45→  input?: Record<string, unknown>;
 46→};
 47→
 48→export async function createTrace(
 49→  surreal: Surreal,
 50→  params: CreateTraceParams,
 51→): Promise<RecordId<"trace", string>> {
 52→  const id = crypto.randomUUID();
 53→  const record = new RecordId("trace", id);
 54→
 55→  const content: Record<string, unknown> = {
 56→    type: params.type,
 57→    actor: params.actor,
 58→    workspace: params.workspace,
 59→    created_at: new Date(),
 60→  };
 61→
 62→  if (params.session) content.session = params.session;
 63→  if (params.parent_trace) content.parent_trace = params.parent_trace;
 64→  if (params.tool_name) content.tool_name = params.tool_name;
 65→  if (params.input) content.input = params.input;
 66→
 67→  await surreal.query("CREATE $record CONTENT $content;", { record, content });
 68→
 69→  return record;
 70→}
 71→
 72→// --- Query Functions ---
 73→
 74→export async function createIntent(
 75→  surreal: Surreal,
 76→  params: CreateIntentParams,
 77→): Promise<RecordId<"intent", string>> {
 78→  const now = new Date();
 79→  const id = crypto.randomUUID();
 80→  const record = new RecordId("intent", id);
 81→
 82→  const content: Record<string, unknown> = {
 83→    goal: params.goal,
 84→    reasoning: params.reasoning,
 85→    status: "draft" satisfies IntentStatus,
 86→    priority: params.priority,
 87→    action_spec: params.action_spec,
 88→    trace_id: params.trace_id,
 89→    requester: params.requester,
 90→    workspace: params.workspace,
 91→    created_at: now,
 92→  };
 93→
 94→  if (params.budget_limit) {
 95→    content.budget_limit = params.budget_limit;
 96→  }
 97→  if (params.expiry) {
 98→    content.expiry = params.expiry;
 99→  }
100→  if (params.authorization_details) {
101→    content.authorization_details = params.authorization_details;
102→  }
103→  if (params.dpop_jwk_thumbprint) {
104→    content.dpop_jwk_thumbprint = params.dpop_jwk_thumbprint;
105→  }
106→
107→  await surreal.query(
108→    "CREATE $record CONTENT $content;",
109→    { record, content },
110→  );
111→
112→  return record;
113→}
114→
115→export async function getIntentById(
116→  surreal: Surreal,
117→  intentId: string,
118→): Promise<IntentRecord | undefined> {
119→  const record = new RecordId("intent", intentId);
120→  const [rows] = await surreal.query<[IntentRecord[]]>(
121→    "SELECT * FROM $record;",
122→    { record },
123→  );
124→  return rows[0];
125→}
126→
127→export async function updateIntentStatus(
128→  surreal: Surreal,
129→  intentId: string,
130→  newStatus: IntentStatus,
131→  updates?: StatusUpdateFields,
132→): Promise<{ ok: true; record: IntentRecord } | { ok: false; error: string }> {
133→  const existing = await getIntentById(surreal, intentId);
134→  if (!existing) {
135→    return { ok: false, error: `Intent ${intentId} not found` };
136→  }
137→
138→  const transition = transitionStatus(existing.status, newStatus);
139→  if (!transition.ok) {
140→    return { ok: false, error: transition.error };
141→  }
142→
143→  const record = new RecordId("intent", intentId);
144→  const now = new Date();
145→
146→  const setFields: Record<string, unknown> = {
147→    status: newStatus,
148→    updated_at: now,
149→  };
150→
151→  if (updates?.evaluation) {
152→    setFields.evaluation = updates.evaluation;
153→  }
154→  if (updates?.veto_expires_at) {
155→    setFields.veto_expires_at = updates.veto_expires_at;
156→  }
157→  if (updates?.veto_reason) {
158→    setFields.veto_reason = updates.veto_reason;
159→  }
160→  if (updates?.error_reason) {
161→    setFields.error_reason = updates.error_reason;
162→  }
163→
164→  const [rows] = await surreal.query<[IntentRecord[]]>(
165→    "UPDATE $record MERGE $fields RETURN AFTER;",
166→    {
167→      record,
168→      fields: setFields,
169→    },
170→  );
171→
172→  return { ok: true, record: rows[0] };
173→}
174→
175→export async function recordTokenIssuance(
176→  surreal: Surreal,
177→  intentId: string,
178→  tokenIssuedAt: Date,
179→  tokenExpiresAt: Date,
180→): Promise<void> {
181→  const record = new RecordId("intent", intentId);
182→  await surreal.query(
183→    "UPDATE $record MERGE $fields;",
184→    {
185→      record,
186→      fields: {
187→        token_issued_at: tokenIssuedAt,
188→        token_expires_at: tokenExpiresAt,
189→      },
190→    },
191→  );
192→}
193→
194→export async function listPendingIntents(
195→  surreal: Surreal,
196→  workspaceId: string,
197→): Promise<IntentRecord[]> {
198→  const workspace = new RecordId("workspace", workspaceId);
199→  const [rows] = await surreal.query<[IntentRecord[]]>(
200→    `SELECT * FROM intent
201→     WHERE workspace = $workspace
202→       AND status = "pending_veto"
203→     ORDER BY created_at DESC;`,
204→    { workspace },
205→  );
206→  return rows;
207→}
208→
209→export async function queryExpiredVetoIntents(
210→  surreal: Surreal,
211→): Promise<IntentRecord[]> {
212→  const [rows] = await surreal.query<[IntentRecord[]]>(
213→    `SELECT * FROM intent
214→     WHERE status = "pending_veto"
215→       AND veto_expires_at < time::now();`,
216→  );
217→  return rows;
218→}
219→
220→export async function listIntentsByWorkspace(
221→  surreal: Surreal,
222→  workspaceId: string,
223→  filters?: ListFilters,
224→): Promise<IntentRecord[]> {
225→  const workspace = new RecordId("workspace", workspaceId);
226→  const limit = filters?.limit ?? 50;
227→
228→  if (filters?.status) {
229→    const [rows] = await surreal.query<[IntentRecord[]]>(
230→      `SELECT * FROM intent
231→       WHERE workspace = $workspace
232→         AND status = $status
233→       ORDER BY created_at DESC
234→       LIMIT $limit;`,
235→      { workspace, status: filters.status, limit },
236→    );
237→    return rows;
238→  }
239→
240→  const [rows] = await surreal.query<[IntentRecord[]]>(
241→    `SELECT * FROM intent
242→     WHERE workspace = $workspace
243→     ORDER BY created_at DESC
244→     LIMIT $limit;`,
245→    { workspace, limit },
246→  );
247→  return rows;
248→}
